#include <stdio.h>
#include <math.h>

int main(void) {
    int n;
    double sum = 0.0;

    // Read integer n from input
    scanf("%d", &n);

    // Calculate and print the sum of the series
    for (int i = 1; i <= n; i++) {
        double numerator = 2 * i + 1;
        double denominator = i * i - 1;
        double term = numerator / denominator;

        // Apply alternating signs
        if (i % 2 == 0) {
            term *= -1;
        }

        sum += term;
    }

    // Output the result with precision
    printf("%.3f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        // Print leading spaces to center the digits
        for (int j = 0; j < n - i; j++) {
            printf(" ");
        }

        // Print the current row of digits
        for (int k = 0; k < i; k++) {
            printf("%d", i);
        }

        // Move to the next line after each row
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <math.h>

double calculateArea(double a, double b, double c) {
    double s = (a + b + c) / 2.0;
    return sqrt(s * (s - a) * (s - b) * (s - c));
}

int areCollinear(double x1, double y1, double x2, double y2, double x3, double y3) {
    return (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) == 0;
}

